;-------------\;  RDTIM0      >;=============/; Lecture du temps coul sur le timer 0 (unit: 128 us), depuis; la dernire lecture. Mise  jour d'un registre interne; Routine appelle pendant la gestion des commutations de processus; en mode superviseur IOF.; In	LASTTIM0.W	Dernier relev; Out	LASTTIM0.W	Mis  jour;	D0.W		Temps prsent sur le timer;	D1.L		Temps coul depuis la dernire lecture; Mod	D0,D1; Sur le Smaky 100, on utilise le TIM1 du Synertek 6522 (1.25 us de clock).; Comme l'chantillonage se fait toutes les 20 ms, le maximum du timer; de 65 ms suffit.RDTIM0:;;-	CLR.W	D0		; Nettoie le chenis;;-PUSH.W SF	;;;;;-OR.W SF,#H'700	;;;;;-	LOAD.B	D0,VIA0+OVT1CL	; D0.B <-- 1er low (unit: 1 us);;-	LOAD.B	D1,VIA0+OVT1CH	; D1.[23..16] <-- 1er high (unit: 256 us);;-	SWAP.W	D1;;-	LOAD.B	D1,VIA0+OVT1CL	; D1.[0..7] <-- 2me low;;-	SWAP.W	D0		; D0.[23..16] <-- 1er low;;-	LOAD.B	D0,VIA0+OVT1CH	; D0.[0..7] <-- 2me high;;-POP.W SF	;;;;;-	SWAP.W	D1		; D1.[0..7] <-- 1er high;;-	COMP.B	D1,D0		; 1er high = 2me high ?;;-	JUMPR',EQ 50$		; oui ==> 2me low correct;;-				; non ==> transition, 1er low OK;;-	EX.L	D0,D1		; D0 = high, D1 = low;;-50$:				; Les 2 high identiques ==> 2me low OK;;-	SWAP.W	D1		; D1.B <-- 2me low;;-				; D0.B <-- 2me high (=1er high);;-	RLX.B	D1,#1		; F:X  <-- bit d'unit 128 us;;-	RLX.W	D0,#1		; D0.[1..8] <-- high;;-				; Valeur effective: 128 us  65.536 ms;;-	LOAD.W	D1,LASTTIM0	; D1.L <-- Dernier relev du dcompteur;;-	LOAD.W	LASTTIM0,D0	; Met  jour le relev du dcompteur;;-	SUB.W	D1,D0		; D1.L <-- Temps supplmentaire coul;;-	AND.L	D1,#2^9-1	; Sortie sur 9 bits;;-	RET	CLR.32	D1	CLR.32	D0		; Nettoie le chenis	MOVE.8	VIA0+OVT1CH,D0	; D1.[23..16] <-- high (unit: 1.25*256=320 us)	MOVE.16	LASTTIM0,D1	; D1.L <-- Dernier relev du dcompteur	MOVE.16	D0,LASTTIM0	; Met  jour le relev du dcompteur	SUB.8	D0,D1		; D1.L <-- Temps supplmentaire coul	MOVE.16	D1,D0		; D1: 0 us  81.92 ms (incrments: 320 us)	SL.16	#1,D1		; D1.[1..8] <-- high (unit: 160 us)	SR.16	#1,D0		; D0 = 0.25 * D1  ( (=D1/2)/2 )	JUMP,CC 80$		; pas de reste => ok on aditionne	TEST.8	TIM0ARR+1:#0	; il y a un reste => on arrondit 1 fois sur 2 !	JUMP,BS 70$	ADDX.16	D0,D1		; correction d'unit: [160us]*1/1.25 --> [128us]	INC.16	TIM0ARR		; on a arrondi	JUMP	90$70$:	INC.16	TIM0ARR		; on n'a pas arrondi (mais compte quand mme)80$:	ADD.16	D0,D1		; correction d'unit: [160us]*1/1.25 --> [128us]90$:	RET